<?php
namespace App\Domain\Shops\Admin;
use App\Domain\Media\MediaAssetType;use App\Domain\Shops\ShopCatalogValidator;use App\Domain\Shops\ShopLocationType;use App\Domain\Shops\ShopPurchaseRate;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Npc;use App\Models\Shop;use App\Models\ShopLocation;use App\Models\Zone;use Carbon\CarbonImmutable;use Carbon\CarbonInterface;use Illuminate\Support\Str;use InvalidArgumentException;
final class ShopAdminService{private $validator;private $media;private $rates;public function __construct(ShopCatalogValidator $validator,ShopMediaService $media,ShopPurchaseRate $rates){$this->validator=$validator;$this->media=$media;$this->rates=$rates;}public function save(array $data,Shop $shop=null){$banner=isset($data['shop_banner'])?$data['shop_banner']:null;$background=isset($data['shop_background'])?$data['shop_background']:null;$removeBanner=!empty($data['remove_shop_banner']);$removeBackground=!empty($data['remove_shop_background']);$zones=isset($data['zone_ids'])?$data['zone_ids']:[];unset($data['shop_banner'],$data['shop_background'],$data['remove_shop_banner'],$data['remove_shop_background'],$data['zone_ids']);$data['purchase_rate_basis_points']=$this->rates->toBasisPoints($data['purchase_rate_percent']);unset($data['purchase_rate_percent']);$data['buys_items']=(bool)$data['buys_items'];$data['code']=$this->code($data['code']);$data['starts_at']=$this->date(isset($data['starts_at'])?$data['starts_at']:null);$data['ends_at']=$this->date(isset($data['ends_at'])?$data['ends_at']:null);return$this->media->persist(function()use($data,$shop,$zones){Npc::whereKey($data['npc_id'])->firstOrFail();$model=$shop&&$shop->exists?Shop::whereKey($shop->id)->lockForUpdate()->firstOrFail():new Shop();$duplicate=Shop::where('code',$data['code'])->when($model->exists,function($query)use($model){$query->where('id','<>',$model->id);})->exists();if($duplicate)throw new InvalidArgumentException('El código normalizado de la Shop ya existe.');$model->fill($data);$this->validator->validateShop($model);$model->save();$this->syncZones($model,$zones);return$model;},[MediaAssetType::BANNER=>['file'=>$banner,'remove'=>$removeBanner],MediaAssetType::BACKGROUND=>['file'=>$background,'remove'=>$removeBackground]]);}public function activate(Shop $shop){return$this->status($shop,CatalogStatus::ACTIVE);}public function deactivate(Shop $shop){return$this->status($shop,CatalogStatus::INACTIVE);}public function hide(Shop $shop){return$this->status($shop,CatalogStatus::HIDDEN);}private function status(Shop $shop,$status){$data=$shop->only(['code','name','description','npc_id','buys_items','sort_order']);$data['purchase_rate_percent']=$this->rates->toPercentage((int)$shop->purchase_rate_basis_points);$data['starts_at']=$shop->starts_at;$data['ends_at']=$shop->ends_at;$data['status']=$status;$data['zone_ids']=$shop->locations()->where('locatable_type',ShopLocationType::ZONE)->pluck('locatable_id')->all();return$this->save($data,$shop);}private function syncZones(Shop $shop,array $ids){$ids=array_values(array_unique(array_map('intval',$ids)));foreach($ids as$id)if($id<=0)throw new InvalidArgumentException('Zone inválida.');if(Zone::whereIn('id',$ids)->count()!==count($ids))throw new InvalidArgumentException('Una Zone seleccionada no existe.');$existing=$shop->locations()->where('locatable_type',ShopLocationType::ZONE)->get()->keyBy('locatable_id');$shop->locations()->where('locatable_type',ShopLocationType::ZONE)->whereNotIn('locatable_id',$ids?:[0])->delete();foreach($ids as$index=>$id){$location=$existing->get($id)?:new ShopLocation(['shop_id'=>$shop->id,'locatable_type'=>ShopLocationType::ZONE,'locatable_id'=>$id]);$location->status=CatalogStatus::ACTIVE;$location->sort_order=$index;$this->validator->validateLocation($location);$location->save();}}private function code($value){$code=Str::slug(trim((string)$value));if($code===''||strlen($code)>64)throw new InvalidArgumentException('Código de Shop inválido.');return$code;}private function date($value){if($value===null||$value==='')return null;if($value instanceof CarbonInterface)return CarbonImmutable::instance($value);return CarbonImmutable::createFromFormat('Y-m-d\TH:i',(string)$value,'UTC');}}
